import hashlib
import os
import subprocess
import sys
from pathlib import Path

AC_UID = "dedf5c87c616ea7b"
AC_TYPE = "data"

SCRIPT = str(Path(__file__).parent.parent.parent.parent / "scripts" / "execute-push.py")
REPO_ROOT = str(Path(__file__).parent.parent.parent.parent)


def _compute_repo_hash() -> str:
    real_root = os.path.realpath(REPO_ROOT)
    return hashlib.sha256(real_root.encode()).hexdigest()[:16]


def test_AC3():
    """
    GIVEN: CLAUDE_SESSION_ID is unset; repo-hash argument is the correct computed hash for the current repo (so SESSION_ID check fires before repo-hash check per required validation order: env var checked first)
    WHEN:  CLAUDE_SESSION_ID= python3 scripts/execute-push.py --request-id abc --repo-hash $(printf '%s' "$(realpath "$(git rev-parse --show-toplevel)")") | sha256sum | cut -c1-16) --remote origin is run
    THEN:  exit code is 2 and stderr contains "CLAUDE_SESSION_ID"
    """
    repo_hash = _compute_repo_hash()
    # Build env without CLAUDE_SESSION_ID
    env = {k: v for k, v in os.environ.items() if k != "CLAUDE_SESSION_ID"}
    result = subprocess.run(
        [sys.executable, SCRIPT,
         "--request-id", "abc",
         "--repo-hash", repo_hash,
         "--remote", "origin"],
        capture_output=True,
        text=True,
        env=env,
        cwd=REPO_ROOT,
    )
    assert result.returncode == 2, f"Expected exit 2, got {result.returncode}. stderr: {result.stderr}"
    assert "CLAUDE_SESSION_ID" in result.stderr, (
        f"Expected 'CLAUDE_SESSION_ID' in stderr, got: {result.stderr}"
    )
